function ckdEpiCr2021(age,sex,scr){const k=sex==='f'?0.7:0.9,a=sex==='f'?-0.241:-0.302;return 142*Math.pow(Math.min(scr/k,1),a)*Math.pow(Math.max(scr/k,1),-1.2)*Math.pow(0.9938,age)*(sex==='f'?1.012:1);}
function ckdEpiCrCys2021(age,sex,scr,cys){const k=sex==='f'?0.7:0.9,a=sex==='f'?-0.219:-0.144;return 135*Math.pow(Math.min(scr/k,1),a)*Math.pow(Math.max(scr/k,1),-0.544)*Math.pow(Math.min(cys/0.8,1),-0.323)*Math.pow(Math.max(cys/0.8,1),-0.778)*Math.pow(0.9961,age)*(sex==='f'?0.963:1);}
function mostellerBSA(heightCm,weightKg){return Math.sqrt(heightCm*weightKg/3600);}
function cockcroftGault(age,sex,weight,scr){return ((140-age)*weight)/(72*scr)*(sex==='f'?0.85:1);}
function selectCockcroftEstimate(mode,actual,ideal,adjusted){if(mode==='actual')return {label:'actual weight',value:actual};if(mode==='ideal'&&ideal!==null)return {label:'ideal weight per selected protocol',value:ideal};if(mode==='adjusted'&&adjusted!==null)return {label:'AdjBW0.4 per selected obesity protocol',value:adjusted};return null;}
function cockcroftWeightOptions(heightCm,weightKg,sex){const heightIn=heightCm/2.54,ibw=heightIn>=60?((sex==='f'?45.5:50)+2.3*(heightIn-60)):null,bmi=weightKg/Math.pow(heightCm/100,2);return {ibw,idealAllowed:ibw!==null&&weightKg>=ibw,adjustedAllowed:ibw!==null&&bmi>=30,bmi};}
function updateCockcroftWeightOptions(){const height=calcReadNumber('rn_height'),weight=calcReadNumber('rn_weight'),sex=document.getElementById('rn_sex')?.value||'f',select=document.getElementById('rn_cg_weight');if(!select||!height||!weight)return;const rules=cockcroftWeightOptions(height,weight,sex),ideal=select.querySelector('option[value="ideal"]'),adjusted=select.querySelector('option[value="adjusted"]');if(ideal)ideal.disabled=!rules.idealAllowed;if(adjusted)adjusted.disabled=!rules.adjustedAllowed;if((select.value==='ideal'&&!rules.idealAllowed)||(select.value==='adjusted'&&!rules.adjustedAllowed))select.value='all';}
