var CLINICAL_CALCULATOR_RETURN_FOCUS=null;
function calculatorFocusable(root){return [...root.querySelectorAll('button:not([disabled]),input:not([disabled]),select:not([disabled]),a[href],[tabindex]:not([tabindex="-1"])')].filter(el=>el.offsetParent!==null);}
function trapCalculatorFocus(e,root){if(e.key!=='Tab')return;const items=calculatorFocusable(root);if(!items.length)return;const first=items[0],last=items[items.length-1];if(!root.contains(document.activeElement)){e.preventDefault();(e.shiftKey?last:first).focus();return;}if(e.shiftKey&&document.activeElement===first){e.preventDefault();last.focus();}else if(!e.shiftKey&&document.activeElement===last){e.preventDefault();first.focus();}}
function clinicalCalculatorDialogKeydown(e){const ov=document.getElementById('calcToolOv');if(!ov||document.getElementById('calculatorConceptOv'))return;if(e.key==='Escape'){e.preventDefault();closeClinicalCalculator();return;}trapCalculatorFocus(e,ov);}
function activateClinicalCalculatorDialog(ov,focus,returnFocus){CLINICAL_CALCULATOR_RETURN_FOCUS=returnFocus||document.activeElement;ov.setAttribute('role','dialog');ov.setAttribute('aria-modal','true');const h=ov.querySelector('.calc-tool-head h3'),close=ov.querySelector('.calc-tool-head button'),card=focus?ov.querySelector(`.calc-tool[data-tool="${focus}"]`):null,target=card?.querySelector('h4')||close;if(h){h.id='clinicalCalculatorTitle';ov.setAttribute('aria-labelledby',h.id);}if(close)close.id='clinicalCalculatorClose';if(card){card.classList.add('focus');if(target)target.tabIndex=-1;}document.removeEventListener('keydown',clinicalCalculatorDialogKeydown);document.addEventListener('keydown',clinicalCalculatorDialogKeydown);setTimeout(()=>{card?.scrollIntoView({block:'center'});target?.focus();},20);}
function deactivateClinicalCalculatorDialog(restoreFocus=true){document.removeEventListener('keydown',clinicalCalculatorDialogKeydown);if(typeof closeCalculatorConcept==='function')closeCalculatorConcept(false);const saved=CLINICAL_CALCULATOR_RETURN_FOCUS;CLINICAL_CALCULATOR_RETURN_FOCUS=null;if(restoreFocus&&saved)setTimeout(()=>{const target=saved==='resident-tools'?document.querySelector('[aria-label="Resident tools"]'):saved;if(target&&target.isConnected)target.focus();},20);}
